// Hitung peluang
export function hitungPeluang(skorUser, skorProdi) {
  const diff = skorUser - skorProdi;
  if (diff >= 50) return 95;
  if (diff >= 30) return 85;
  if (diff >= 15) return 72;
  if (diff >= 0) return 58;
  if (diff >= -15) return 40;
  if (diff >= -30) return 25;
  if (diff >= -50) return 12;
  return 5;
}
